diff --git a/lustre/lod/lod_qos.c b/lustre/lod/lod_qos.c
index c4995b203d..0dc9bf30f0 100644
--- a/lustre/lod/lod_qos.c
+++ b/lustre/lod/lod_qos.c
@@ -2078,7 +2078,7 @@ __u16 lod_get_stripe_count_plain(struct lod_device *lod, struct lod_object *lo,
                        if (stripe_count >= LOV_ALL_STRIPES_MIN &&
                            stripe_count <= LOV_ALL_STRIPES_MAX) {
                                stripe_count =
-                                   ((LOV_ALL_STRIPES_MAX - stripe_count) + 1) *
+                                   (LOV_ALL_STRIPES_MAX - stripe_count + 1) *
                                    lov_desc->ld_active_tgt_count;
                        }
                } else {
@@ -2092,6 +2092,9 @@ __u16 lod_get_stripe_count_plain(struct lod_device *lod, struct lod_object *lo,
                }
        }

+       if (!stripe_count)
